        self.client.write_file(remote_path, content_b64)
        return True

    def run(self, command: str) -> dict[str, Any]:
        self._ensure_client()
        return self.client.execute_command(command)

    def stop(self):
        if self.client:
            self.client.stop()


def build_react_agent(llm, system_prompt: str):
    tools = []
    agent = create_react_agent(llm, tools=tools)
    system_message = SystemMessage(content=system_prompt)
    return agent


def invoke_react_agent(agent, user_text: str) -> str:
    messages = [HumanMessage(content=user_text)]
    result = agent.invoke({"messages": messages})
    for msg in result["messages"]:
        if isinstance(msg, AIMessage):
            return msg.content
    return ""


def build_planner_agent(llm):
    system_prompt = """You are a PCAP analysis planner. Generate Python scripts to analyze PCAP files using scapy or tshark."""
    return build_react_agent(llm, system_prompt)


def build_reporter_agent(llm):
    system_prompt = """You are a security analyst. Generate a summary report from PCAP analysis results."""
    return build_react_agent(llm, system_prompt)


def _plan_script(agent, pcap_local_path: str) -> str:
    user_text = f"Generate a Python script to analyze this PCAP file: {pcap_local_path}"
    return invoke_react_agent(agent, user_text)


def _repair_script(agent, prev_script: str, results: list[dict]) -> str:
    user_text = f"The previous script failed. Results: {results}. Please repair the script:\n{prev_script}"
    return invoke_react_agent(agent, user_text)


def _execute_once_in_runner(runner: SandboxRunner, pcap_local_path: str, script: str) -> list[dict]:
    runner.upload_file(pcap_local_path, "/tmp/analysis.pcap")
    results = []
    steps = script.split("\n\n")
    for step in steps:
        if step.strip():
            result = runner.run(f"python3 -c '{step.replace(chr(39), chr(39) + chr(92) + chr(39) + chr(39))}'")
            results.append(result)
    return results


def _analyze_with_retries(runner: SandboxRunner, pcap_local_path: str, planner, reporter, max_retries: int = 2) -> dict:
    script = _plan_script(planner, pcap_local_path)
    results = []
    for attempt in range(max_retries + 1):
        try:
            results = _execute_once_in_runner(runner, pcap_local_path, script)
            if all(r.get("exit_code") == 0 for r in results):
                break
            if attempt < max_retries:
                script = _repair_script(planner, script, results)
        except CommandExecutionError as e:
            if attempt < max_retries:
                script = _repair_script(planner, script, [{"error": str(e)}])
            else:
                raise
    return {"script": script, "results": results}


def _report(reporter, results: list[dict]) -> str:
    user_text = f"Generate a report from these results: {results}"
    return invoke_react_agent(reporter, user_text)


class AnalyzeResponse(BaseModel):
    script: str
    results: list[dict[str, Any]]
    report: str


app = FastAPI(title="PCAP Analyzer")


@app.on_event("startup")
def startup_event():
    global PLANNER, REPORTER
    if not API_KEY:
        raise ValueError("OPENAI_API_KEY is required")
    llm = ChatOpenAI(api_key=API_KEY, base_url=API_BASE_URL, model=MODEL_NAME)
    PLANNER = build_planner_agent(llm)
    REPORTER = build_reporter_agent(llm)


@app.post("/analyze", response_model=AnalyzeResponse)
def analyze(
    pcap_file: UploadFile = File(None),
    pcap_path: str = Form(None),
):
    if not pcap_file and not pcap_path:
        raise HTTPException(400, "Either pcap_file or pcap_path must be provided")

    temp_file = None
    try:
        if pcap_file:
            temp_file = tempfile.NamedTemporaryFile(delete=False, suffix=".pcap")
            temp_file.write(pcap_file.file.read())
            temp_file.close()
            pcap_local_path = temp_file.name
        else:
            pcap_local_path = pcap_path

        runner = SandboxRunner(
            name=CODEINTERPRETER_NAME,
            namespace=SANDBOX_NAMESPACE,
            warmup_sec=SANDBOX_WARMUP_SEC,
        )

        try:
            analysis = _analyze_with_retries(runner, pcap_local_path, PLANNER, REPORTER)
            report = _report(REPORTER, analysis["results"])

            return AnalyzeResponse(
                script=analysis["script"],
                results=analysis["results"],
                report=report,
            )
        finally:
            runner.stop()
    except Exception as e:
        raise HTTPException(500, str(e))
    finally:
        if temp_file:
            os.unlink(temp_file.name)


if __name__ == "__main__":
    uvicorn.run(app, host=SERVER_HOST, port=SERVER_PORT, reload=SERVER_RELOAD)

