class ControlPlaneClient:
    def __init__(self, workload_manager_url: Optional[str] = None, auth_token: Optional[str] = None):
        self.workload_manager_url = workload_manager_url or os.getenv("WORKLOAD_MANAGER_URL")
        if not self.workload_manager_url:
            raise ValueError("workload_manager_url is required")

        if auth_token:
            self.auth_token = auth_token
        else:
            self.auth_token = read_token_from_file("/var/run/secrets/kubernetes.io/serviceaccount/token")

        self.session = requests.Session()
        if self.auth_token:
            self.session.headers["Authorization"] = f"Bearer {self.auth_token}"

    def create_session(self, name: str, namespace: str, metadata: Optional[dict] = None, ttl: int = 3600) -> str:
        url = f"{self.workload_manager_url}/v1/code-interpreter"
        data = {"name": name, "namespace": namespace, "ttl": ttl}
        if metadata:
            data["metadata"] = metadata
        response = self.session.post(url, json=data, timeout=30)
        response.raise_for_status()
        data = response.json()
        session_id = data.get("sessionId")
        if not session_id:
            raise ValueError("sessionId not found in response")
        return session_id

    def delete_session(self, session_id: str) -> bool:
        url = f"{self.workload_manager_url}/v1/code-interpreter/sessions/{session_id}"
        response = self.session.delete(url, timeout=30)
        if response.status_code == 404:
            return True
        response.raise_for_status()
        return True

    def close(self):
        self.session.close()

