class CodeInterpreterDataPlaneClient:
    def __init__(
        self,
        router_url: str,
        namespace: str,
        cr_name: str,
        session_id: str,
        timeout: int = 120,
        connect_timeout: float = 5.0,
    ):
        base_url = urljoin(router_url, f"/v1/namespaces/{namespace}/code-interpreters/{cr_name}/invocations/")
        self.base_url = base_url
        self.session, self.timeout = create_session(timeout, connect_timeout)
        self.session.headers["x-agentcube-session-id"] = session_id

    def _request(self, method: str, path: str, **kwargs: Any) -> requests.Response:
        url = urljoin(self.base_url, path)
        kwargs["timeout"] = self.timeout
        response = self.session.request(method, url, **kwargs)
        response.raise_for_status()
        return response

    def execute_command(self, command: str, timeout: Optional[int] = None) -> dict[str, Any]:
        payload = {"command": command.split()}
        if timeout:
            payload["timeout"] = f"{timeout}s"
        response = self._request("POST", "api/execute", json=payload)
        result = response.json()
        if result.get("exit_code", 0) != 0:
            raise CommandExecutionError(
                exit_code=result.get("exit_code", 0),
                stderr=result.get("stderr", ""),
                command=command,
            )
        return result

    def write_file(self, path: str, content: str, mode: str = "0644") -> None:
        import base64
        content_b64 = base64.b64encode(content.encode("utf-8")).decode("utf-8")
        payload = {"path": path, "content": content_b64, "mode": mode}
        self._request("POST", "api/files", json=payload)

    def upload_file(self, local_path: str, remote_path: str) -> None:
        with open(local_path, "rb") as f:
            files = {"file": (remote_path, f)}
            data = {"path": remote_path}
            self._request("POST", "api/files", files=files, data=data)

    def download_file(self, remote_path: str, local_path: str) -> None:
        response = self._request("GET", f"api/files/{remote_path}", stream=True)
        with open(local_path, "wb") as f:
            for chunk in response.iter_content(chunk_size=8192):
                f.write(chunk)

    def list_files(self, path: str) -> list[dict[str, Any]]:
        response = self._request("GET", "api/files", params={"path": path})
        return response.json().get("files", [])

    def close(self):
        self.session.close()

