from typing import Optional, Dict, Any


class DockerService:
    def __init__(self):
        self.client = docker.from_env()

    def check_docker_available(self):
        try:
            self.client.ping()
        except Exception as e:
            raise RuntimeError(f"Docker is not available: {e}")

    def build_image(
        self,
        workspace_path: str,
        image_name: str,
        tag: str,
        buildargs: Optional[Dict[str, str]] = None,
    ) -> Dict[str, Any]:
        import time
        start_time = time.time()
        image, logs = self.client.images.build(
            path=workspace_path,
            tag=f"{image_name}:{tag}",
            buildargs=buildargs or {},
            rm=True,
        )
        build_time = time.time() - start_time
        return {
            "image_name": image_name,
            "image_id": image.id,
            "image_size": image.attrs.get("Size", 0),
            "build_time": build_time,
        }

    def push_image(
        self,
        image_name: str,
        registry_url: Optional[str] = None,
        username: Optional[str] = None,
        password: Optional[str] = None,
    ) -> Dict[str, Any]:
        import time
        start_time = time.time()
        if username and password:
            self.client.login(username=username, password=password)
        push_image_name = f"{registry_url}/{image_name}" if registry_url else image_name
        logs = self.client.images.push(push_image_name)
        return {
            "pushed_image": push_image_name,
            "push_time": time.time() - start_time,
        }

    def remove_image(self, image_name: str) -> bool:
        try:
            self.client.images.remove(image_name, force=True)
            return True
        except Exception:
            return False

